INSERT INTO public.associate_entity_master (layer_id, associate_layer_id, is_enabled, created_on, created_by, modified_on, modified_by, is_snapping_enabled, is_shifting_allowed) 
VALUES((select layer_id from layer_details where layer_name='Tree'), (select layer_id from layer_details where layer_name='BDB'), true, now(), 0, now(), 0, false, true);

update associate_entity_master set is_shifting_allowed=true where layer_id=(select layer_id from layer_details where layer_name='Tree') and associate_layer_id in(select layer_id from layer_details where layer_name in('SpliceClosure','ADB','CDB','FDB','BDB'));